import java.util.*;

public class TwoSum {

    // Returns all unique pairs that sum to target
    public static List<int[]> twoSumPairs(int[] nums, int target) {
        Set<Integer> seen      = new HashSet<>();
        Set<String>  usedPairs = new HashSet<>();
        List<int[]>  result    = new ArrayList<>();

        for (int num : nums) {
            int complement = target - num;
            if (seen.contains(complement)) {
                int a = Math.min(num, complement);
                int b = Math.max(num, complement);
                String key = a + "," + b;
                if (usedPairs.add(key))      // add returns false if already present
                    result.add(new int[]{a, b});
            }
            seen.add(num);
        }
        return result;
    }

    public static void main(String[] args) {
        int[] nums = {1, 4, 3, 2, 7, 5};
        int target = 6;
        for (int[] p : twoSumPairs(nums, target))
            System.out.println("[" + p[0] + ", " + p[1] + "]");
        // Output: [1,5]  [4,2]  [3,3 skipped]
    }
}

import java.util.*;

public class PythagoreanTriples {

    public static List<int[]> findTriples(int[] arr) {
        List<int[]> result = new ArrayList<>();
        Set<Long> squares = new HashSet<>();

        for (int x : arr) squares.add((long) x * x);

        Arrays.sort(arr);   // optional: for ordered output
        int n = arr.length;

        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                long sumSq = (long) arr[i] * arr[i] + (long) arr[j] * arr[j];
                if (squares.contains(sumSq))
                    result.add(new int[]{arr[i], arr[j], (int) Math.sqrt(sumSq)});
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int[] arr = {3, 5, 4, 8, 6, 10};
        for (int[] t : findTriples(arr))
            System.out.printf("(%d, %d, %d)%n", t[0], t[1], t[2]);
        // Output: (3,4,5)  (6,8,10)
    }
}

public class MoveZeroes {

    public static void moveZeroes(int[] nums) {
        int write = 0;
        for (int num : nums)
            if (num != 0) nums[write++] = num;
        while (write < nums.length)
            nums[write++] = 0;
    }

    public static void main(String[] args) {
        int[] arr = {0, 1, 0, 3, 12};
        moveZeroes(arr);
        System.out.println(Arrays.toString(arr)); // [1, 3, 12, 0, 0]
    }
}

