public class MaxMeetings {

    public static int maxMeetings(int[] start, int[] end) {
        int n = start.length;
        Integer[] idx = new Integer[n];
        for (int i = 0; i < n; i++) idx[i] = i;

        Arrays.sort(idx, (a, b) -> end[a] != end[b] ? end[a] - end[b] : start[a] - start[b]);

        int count = 1, lastEnd = end[idx[0]];
        for (int i = 1; i < n; i++) {
            if (start[idx[i]] > lastEnd) {
                count++;
                lastEnd = end[idx[i]];
            }
        }
        return count;
    }

    public static void main(String[] args) {
        int[] s = {1,3,0,5,8,5};
        int[] e = {2,4,6,7,9,9};
        System.out.println(maxMeetings(s, e)); // 4
    }
}

public class AnagramCheck {

    public static boolean isAnagram(String s, String t) {
        if (s.length() != t.length()) return false;
        int[] freq = new int[26];
        for (int i = 0; i < s.length(); i++) {
            freq[s.charAt(i) - 'a']++;
            freq[t.charAt(i) - 'a']--;
        }
        for (int f : freq) if (f != 0) return false;
        return true;
    }

    public static void main(String[] args) {
        System.out.println(isAnagram("anagram", "nagaram")); // true
        System.out.println(isAnagram("rat", "car"));         // false
    }
}

public class CaesarCipher {

    // Decode the full ciphertext given one known original word
    public static String decode(String cipher, String knownWord) {
        char cipherChar = char(cipher.toLowerCase().charAt(0));
        char plainChar  = knownWord.toLowerCase().charAt(0);
        int  shift = ((cipherChar - plainChar) + 26) % 26;

        StringBuilder sb = new StringBuilder();
        for (char c : cipher.toCharArray()) {
            if (Character.isLetter(c)) {
                char base = Character.isUpperCase(c) ? 'A' : 'a';
                sb.append((char) ((c - base - shift + 26) % 26 + base));
            } else {
                sb.append(c);   // spaces, punctuation untouched
            }
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String cipher    = "Khoor Zruog";   // "Hello World" shifted by 3
        String knownWord = "Hello";
        System.out.println(decode(cipher, knownWord)); // Hello World
    }
}

