public class RemoveConsecutive {

    private static final Set<Character> SPECIAL =
        new HashSet<>(Arrays.asList('a','b','e','t','i','o'));

    public static String removeConsecutive(String s) {
        StringBuilder sb = new StringBuilder();
        int i = 0, n = s.length();

        while (i < n) {
            char c = s.charAt(i);
            if (SPECIAL.contains(c)) {
                int j = i;
                while (j < n && SPECIAL.contains(s.charAt(j))) j++;
                if (j - i < 2) sb.append(c);  // single special char → keep
                i = j;                              // skip entire run of 2+
            } else {
                sb.append(c);
                i++;
            }
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(removeConsecutive("testing is a boring job"));
        // Output: "sng is a ring j"
    }
}

