public class CapitalizeConsecutive {

    private static final Set<Character> TARGET =
        new HashSet<>(Arrays.asList('a','b','e','i','o','u','s','t'));

    public static String capitalize(String s) {
        char[] arr = s.toCharArray();
        int i = 0, n = arr.length;

        while (i < n) {
            char lc = Character.toLowerCase(arr[i]);
            if (TARGET.contains(lc)) {
                int j = i;
                while (j < n && TARGET.contains(Character.toLowerCase(arr[j]))) j++;
                if (j - i >= 2)
                    for (int k = i; k < j; k++)
                        arr[k] = Character.toUpperCase(arr[k]);
                i = j;
            } else { i++; }
        }
        return new String(arr);
    }

    public static void main(String[] args) {
        System.out.println(capitalize("Testing is boring!"));
        // Output: "TESTIng IS BOring!"
    }
}

