public class CharCount {

    public static Map<Character, Integer> count(String s) {
        Map<Character, Integer> map = new LinkedHashMap<>(); // preserves insertion order
        for (char c : s.toCharArray())
            map.merge(c, 1, Integer::sum);
        return map;
    }

