public class StarOutsidePipe {

    public static int countStars(String s) {
        boolean insidePipe = false;
        int count = 0;
        for (char c : s.toCharArray()) {
            if      (c == '|') insidePipe = !insidePipe;
            else if (c == '*' && !insidePipe) count++;
        }
        return count;
    }

    public static void main(String[] args) {
        String s = "sdff*d|dfd*dsf|df*das*|sdfd**f|";
        System.out.println(countStars(s)); // 3
    }
}

