public class PhoneKeypad {

    private static final String[] MAP = {
        "", "", "abc", "def", "ghi", "jkl",
        "mno", "pqrs", "tuv", "wxyz"
    };

    public static List<String> combinations(String digits) {
        List<String> result = new ArrayList<>();
        if (!digits.isEmpty())
            backtrack(digits, 0, new StringBuilder(), result);
        return result;
    }

    private static void backtrack(String digits, int idx,
                                   StringBuilder current, List<String> result) {
        if (idx == digits.length()) { result.add(current.toString()); return; }
        for (char c : MAP[digits.charAt(idx) - '0'].toCharArray()) {
            current.append(c);
            backtrack(digits, idx + 1, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }

    public static void main(String[] args) {
        System.out.println(combinations("23"));
        // [ad, ae, af, bd, be, bf, cd, ce, cf]
    }
}

public class BinaryEncoder {

    private static final char[] CODES = {'A', 'T', 'C', 'G'}; // index = 00,01,10,11

    public static String encode(String binary) {
        if (binary.length() % 2 != 0) throw new IllegalArgumentException("Even length required");
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < binary.length(); i += 2) {
            int val = (binary.charAt(i) - '0') * 2 + (binary.charAt(i + 1) - '0');
            sb.append(CODES[val]);
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(encode("001011")); // "ATG"  (00→A, 10→C... wait 10→C, 11→G)
        System.out.println(encode("00011011")); // "ATCG"
    }
}

