// Model classes
record Car(int id, String type, String name) {}
record Company(String name, List<Car> cars) {}

public class CarSegregator {

    // Streams approach — concise and readable
    public static Map<String, List<Car>> segregate(List<Company> companies) {
        return companies.stream()
            .flatMap(c -> c.cars().stream())
            .collect(Collectors.groupingBy(Car::type));
    }

    // Explicit HashMap approach (shows logic clearly in interviews)
    public static Map<String, List<Car>> segregateManual(List<Company> companies) {
        Map<String, List<Car>> map = new HashMap<>();
        for (Company co : companies)
            for (Car car : co.cars())
                map.computeIfAbsent(car.type(), k -> new ArrayList<>()).add(car);
        return map;
    }

    public static void main(String[] args) {
        List<Company> data = List.of(
            new Company("TataMotors", List.of(new Car(1,"SUV","Harrier"), new Car(2,"Sedan","Tigor"))),
            new Company("Maruti",    List.of(new Car(3,"SUV","Brezza"), new Car(4,"Hatch","Swift")))
        );
        segregate(data).forEach((type, cars) ->
            System.out.println(type + ": " + cars));
    }
}

public class MirrorTree {

    static class Node {
        int val; Node left, right;
        Node(int v) { val = v; }
    }

    public static Node mirror(Node root) {
        if (root == null) return null;
        Node tmp  = root.left;
        root.left  = mirror(root.right);
        root.right = mirror(tmp);
        return root;
    }
}

