public class Codec {

    static class Node { int val; Node l, r; Node(int v){val=v;} }

    // Serialize: BFS → comma-separated, null = "#"
    public static String serialize(Node root) {
        if (root == null) return "#";
        Queue<Node> q = new LinkedList<>();
        StringBuilder sb = new StringBuilder();
        q.add(root);
        while (!q.isEmpty()) {
            Node n = q.poll();
            if (n == null) { sb.append("#,"); continue; }
            sb.append(n.val).append(',');
            q.add(n.l); q.add(n.r);
        }
        return sb.toString();
    }

    // Deserialize: rebuild level by level
    public static Node deserialize(String data) {
        String[] tokens = data.split(",");
        if (tokens[0].equals("#")) return null;
        Node root = new Node(Integer.parseInt(tokens[0]));
        Queue<Node> q = new LinkedList<>();
        q.add(root);
        int i = 1;
        while (!q.isEmpty() && i < tokens.length) {
            Node n = q.poll();
            if (!tokens[i].equals("#")) { n.l = new Node(Integer.parseInt(tokens[i])); q.add(n.l); }
            i++;
            if (i < tokens.length && !tokens[i].equals("#")) { n.r = new Node(Integer.parseInt(tokens[i])); q.add(n.r); }
            i++;
        }
        return root;
    }
}

