public class FlattenDLL {

    static class Node {
        int val; Node prev, next, child;
        Node(int v) { val = v; }
    }

    public static Node flatten(Node head) {
        if (head == null) return null;
        Deque<Node> stack = new ArrayDeque<>();
        Node curr = head;

        while (curr != null) {
            if (curr.child != null) {
                if (curr.next != null) stack.push(curr.next);
                curr.next = curr.child;
                curr.child.prev = curr;
                curr.child = null;
            }
            if (curr.next == null && !stack.isEmpty()) {
                Node restored = stack.pop();
                curr.next = restored;
                restored.prev = curr;
            }
            curr = curr.next;
        }
        return head;
    }
}

public class ClockAngle {

    public static double angleBetweenHands(int hour, int minute) {
        hour = hour % 12;   // convert 24h → 12h

        // Degrees from 12 o'clock
        double hourDeg   = hour * 30.0 + minute * 0.5;   // 30°/hr, 0.5°/min
        double minuteDeg = minute * 6.0;                  // 6°/min

        double diff = Math.abs(hourDeg - minuteDeg);
        return Math.min(diff, 360.0 - diff);             // shortest angle
    }

    public static void main(String[] args) {
        System.out.println(angleBetweenHands(3, 30));  // 75.0°
        System.out.println(angleBetweenHands(15, 0));  // 90.0°  (15h = 3h)
        System.out.println(angleBetweenHands(12, 0));  // 0.0°
    }
}

public class HourglassPattern {

    public static void print(int n) {
        // Upper half (wide → narrow)
        for (int i = 0; i < n; i++) {
            for (int sp = 0; sp < i; sp++)       System.out.print(" ");
            for (int st = 0; st < 2*(n-i)-1; st++) System.out.print("*");
            System.out.println();
        }
        // Lower half (narrow → wide)
        for (int i = n - 2; i >= 0; i--) {
            for (int sp = 0; sp < i; sp++)       System.out.print(" ");
            for (int st = 0; st < 2*(n-i)-1; st++) System.out.print("*");
            System.out.println();
        }
    }

    public static void main(String[] args) { print(4); }
