       *
      ***
     *****
    *******
    */
}

public class SpiralMatrix {

    public static int[][] generate(int n) {
        int[][] mat = new int[n][n];
        int top = 0, bottom = n-1, left = 0, right = n-1, num = 1;

        while (top <= bottom && left <= right) {
            for (int c = left;   c <= right;  c++) mat[top][c]    = num++;
            for (int r = top+1;  r <= bottom; r++) mat[r][right]   = num++;
            for (int c = right-1; c >= left && top < bottom; c--) mat[bottom][c] = num++;
            for (int r = bottom-1;r >= top+1 && left < right; r--) mat[r][left]   = num++;
            top++; bottom--; left++; right--;
        }
        return mat;
    }

    public static void main(String[] args) {
        for (int[] row : generate(4))
            System.out.println(Arrays.toString(row));
    }
}

