SELECT MAX(marks) FROM students
WHERE marks < (SELECT MAX(marks) FROM students);

-- Generic Nth highest (replace 2 with N)
SELECT marks FROM (
    SELECT DISTINCT marks, DENSE_RANK() OVER (ORDER BY marks DESC) rnk
    FROM students
) t WHERE rnk = 2;

-- Method 1: LEFT JOIN with NULL (most efficient)
SELECT s.*
FROM      students   s
LEFT JOIN departments d ON s.dept_id = d.id
WHERE d.id IS NULL;

-- Method 2: NOT EXISTS (readable)
SELECT * FROM students s
WHERE NOT EXISTS (
    SELECT 1 FROM departments d WHERE d.id = s.dept_id
);

