public class ChefBags {

    public static boolean canTakeAll(int A, int B, int C, int D, int E) {
        // Try each bag as the carry-on; other two are checked
        return  (A <= E && B + C <= D) ||   // carry A, check B+C
                (B <= E && A + C <= D) ||   // carry B, check A+C
                (C <= E && A + B <= D);     // carry C, check A+B
    }

    public static void main(String[] args) {
        System.out.println(canTakeAll(3, 5, 4, 8, 5)); // true: carry 5, check 3+4=7≤8
        System.out.println(canTakeAll(5, 6, 7, 5, 4)); // false
    }
}

/**
 * Evaluates a mathematical expression string.
 * Supports: integers, +, -, *, /, (, )
 * Handles correct operator precedence and parentheses.
 * No eval() — pure stack logic.
 */
function evaluateExpression(expr) {
    const nums = [];   // number stack
    const ops  = [];   // operator stack

    const precedence = (op) => (op === '*' || op === '/') ? 2 : 1;

    const applyOp = () => {
        const b  = nums.pop();
        const a  = nums.pop();
        const op = ops.pop();
        if      (op === '+') nums.push(a + b);
        else if (op === '-') nums.push(a - b);
        else if (op === '*') nums.push(a * b);
        else if (op === '/') nums.push(Math.trunc(a / b));  // integer division
    };

    let i = 0;
    const s = expr.replace(/\s+/g, '');  // strip whitespace

    while (i < s.length) {
        const ch = s[i];

        // ── Parse multi-digit number ──────────────────────────────
        if (ch >= '0' && ch <= '9') {
            let num = 0;
            while (i < s.length && s[i] >= '0' && s[i] <= '9')
                num = num * 10 + Number(s[i++]);
            nums.push(num);
            continue;

        // ── Open paren: push sentinel ─────────────────────────────
        } else if (ch === '(') {
            ops.push('(');

        // ── Close paren: flush until matching '(' ─────────────────
        } else if (ch === ')') {
            while (ops.length && ops[ops.length - 1] !== '(')
                applyOp();
            ops.pop();  // discard '('

        // ── Operator: respect precedence before pushing ───────────
        } else if ('+-*/'.includes(ch)) {
            while (ops.length && ops[ops.length - 1] !== '(' &&
                   precedence(ops[ops.length - 1]) >= precedence(ch))
                applyOp();
            ops.push(ch);
        }
        i++;
    }

    // ── Evaluate remaining operators ──────────────────────────────
    while (ops.length) applyOp();

    return nums[0];
}

// ── Tests ──────────────────────────────────────────────────────
console.log(evaluateExpression("3 + 2 * 4"));           // 11  (not 20)
console.log(evaluateExpression("(3 + 2) * 4"));         // 20
console.log(evaluateExpression("10 + 2 * 6"));           // 22
console.log(evaluateExpression("100 * (2 + 12) / 14"));  // 100
