/**
 * Step 1 — replace every occurrence of the 2-char pattern with '$'.
 * Step 2 — collapse any run of 2+ consecutive '$' → single '$'.
 *
 * Condition 1 example: "ab$$$cd" (pattern "ab") → "$$$cd" → "$cd"
 * Condition 2 example: "$abc$$$c"                → "$abc$c"
 */
function processString(input) {
    if (input.length < 2) return input;

    const pattern = input.slice(0, 2);

    // ── PASS 1: replace pattern occurrences with '$' ───────────
    let replaced = '';
    let i = 0;
    while (i < input.length) {
        if (input.slice(i, i + 2) === pattern) {
            replaced += '$';
            i += 2;                 // consume both chars of pattern
        } else {
            replaced += input[i++]; // keep char as-is
        }
    }

    // ── PASS 2: collapse consecutive '$' runs → single '$' ────
    let collapsed = '';
    let j = 0;
    while (j < replaced.length) {
        collapsed += replaced[j];
        if (replaced[j] === '$') {
            while (j + 1 < replaced.length && replaced[j + 1] === '$')
                j++;  // skip subsequent '$'s in this run
        }
        j++;
    }

    return collapsed;
}

