/**
 * Input : comma-separated string, e.g. "C1,B2,C2,B1,C3,B4,B3"
 * Rules :
 *   - Cap Cn can only fit Bottle Bn (same number)
 *   - Cap must be within 3 positions (before or after) of the bottle
 *   - Bottles without a valid cap are NOT counted
 *   - No cap/bottle number is repeated
 * Output: count of successfully matched bottles
 */
function countMatchedBottles(input) {
    const items = input.split(',').map(s => s.trim());

    const capPos    = {};   // { num: index }
    const bottlePos = {};   // { num: index }

    items.forEach((item, idx) => {
        const type = item[0].toUpperCase();          // 'C' or 'B'
        const num  = parseInt(item.slice(1), 10);  // numeric id
        if      (type === 'C') capPos[num]    = idx;
        else if (type === 'B') bottlePos[num] = idx;
    });

    let count = 0;
    for (const [num, bIdx] of Object.entries(bottlePos)) {
        const cIdx = capPos[num];
        if (cIdx !== undefined && Math.abs(cIdx - bIdx) <= 3)
            count++;
    }
    return count;
}

