/**
 * assignmentObj & studentSubmissionObj structures (as given in the problem):
 *
 * Note: questionId 2 appears twice in the problem — this is intentional duplication
 * in the problem statement. We match questions by their ARRAY INDEX to avoid
 * ambiguity, which is the safest and most predictable approach.
 */

function calculateTotalMarks(assignmentObj, studentSubmissionObj) {
    const questions    = assignmentObj.questions;
    const submissions  = studentSubmissionObj.questions;
    let   totalMarks   = 0;

    for (let i = 0; i < questions.length; i++) {
        const question   = questions[i];
        const submission = submissions[i];

        // Rule: skip TEXT questions entirely
        if (question.type === 'TEXT') continue;

        // Rule: only award marks if submitted answer matches correct answer
        if (submission && submission.submittedAns === question.correctAns)
            totalMarks += question.marks;
    }

    return totalMarks;
}

