/**
 * Finds the array element closest to the given target.
 * Rules:
 *   - No built-in Math functions (Math.abs, Math.min, etc.)
 *   - No sort
 *   - Works with positive and negative numbers
 *   - At least 1 element guaranteed
 *
 * Sample: [6, 3, 9, 14], target = 8  →  Output: 9
 */
function findClosest(arr, target) {
    let closest = arr[0];
    // Manual abs — no Math.abs
    let minDiff = arr[0] >= target ? arr[0] - target : target - arr[0];

    for (let i = 1; i < arr.length; i++) {
        const diff = arr[i] >= target ? arr[i] - target : target - arr[i];

        if (diff < minDiff) {          // strictly less → first of equal-distance wins
            minDiff = diff;
            closest = arr[i];
        }
    }
    return closest;
}

